plist.dict:
CFBundleDevelopmentRegion
$(DEVELOPMENT_LANGUAGE)
CFBundleExecutable
$(EXECUTABLE_NAME)
CFBundleIconFile

CFBundleIdentifier
$(PRODUCT_BUNDLE_IDENTIFIER)
CFBundleInfoDictionaryVersion
6.0
CFBundleDisplayName
{{ cookiecutter.product_name }}
CFBundleName
$(PRODUCT_NAME)
CFBundlePackageType
APPL
CFBundleShortVersionString
$(FLUTTER_BUILD_NAME)
CFBundleVersion
$(FLUTTER_BUILD_NUMBER)
LSMinimumSystemVersion
$(MACOSX_DEPLOYMENT_TARGET)
NSHumanReadableCopyright
$(PRODUCT_COPYRIGHT)
NSMainNibFile
MainMenu
NSPrincipalClass
NSApplication

{% macro render_value(value) -%}
{% if value is string -%}
{{ value }}
{% elif value is boolean -%}
<{{ "true" if value else "false" }}/>
{% elif value is integer -%}
{{ value }}
{% elif value is float -%}
{{ value }}
{% elif value is mapping -%}

	{{ render_dict(value) }}

{% elif value is sequence -%}  {# Support for lists/arrays #}

	{% for item in value -%}
		{{ render_value(item) }}
	{% endfor -%}

{% endif -%}
{% endmacro -%}
{% macro render_dict(d) -%}
{% for key, value in d.items() -%}
{{ key }}
{{ render_value(value) }}
{% endfor -%}
{% endmacro -%}
{{ render_dict(cookiecutter.options.info_plist) }}
